77	    rl.on('close', resolve);
78	
79	    // Propagate stream errors; close readline first to avoid double-resolve.
80	    stream.on('error', (err) => {
81	      rl.close();
82	      reject(err);
83	    });
84	    rl.on('error', reject);
85	  });
86	
87	  const hasMore = entries.length > clampedLimit;
88	  // Remove the extra probe line so callers receive at most clampedLimit entries.
89	  if (hasMore) entries.pop();
