  it('returns true while the process is running', async () => {
    const mgr = new JigProcessManager();
    const handle = await mgr.spawn({
      command: 'node',
      args: ['-e', 'setTimeout(() => process.exit(0), 2000)'],
      cwd: TMP,
      promptBuffer: '',
      gracePeriodMs: 200,
    });

