  it('emits one event per NDJSON line written to stdout', async () => {
    const mgr = new JigProcessManager();
    const script = [
      'process.stdout.write(\'{"type":"text","text":"hello"}\\n\');',
      'process.stdout.write(\'{"type":"text","text":"world"}\\n\');',
